import React, { useState } from 'react';
import { useData } from '../../context/DataContext';

const TaskManager = () => {
  const { staffList, tasks, addTask } = useData();
  
  // State quản lý form, thêm các trường mới
  const [newTask, setNewTask] = useState({
    title: '',
    assigneeId: '',
    startDate: '',
    deadline: '',
    penalty: '' // Hình thức kỷ luật
  });

  const handleCreateTask = (e) => {
    e.preventDefault();
    if (!newTask.assigneeId) return alert("Vui lòng chọn nhân sự!");
    if (!newTask.startDate || !newTask.deadline) return alert("Vui lòng chọn đầy đủ thời gian!");
    
    // Kiểm tra logic: Deadline phải sau ngày bắt đầu
    if (new Date(newTask.deadline) <= new Date(newTask.startDate)) {
      return alert("Hạn chót (Deadline) phải sau thời gian bắt đầu!");
    }

    addTask({ 
      title: newTask.title, 
      assigneeId: parseInt(newTask.assigneeId),
      startDate: newTask.startDate,
      deadline: newTask.deadline,
      penalty: newTask.penalty || 'Khiển trách' // Mặc định nếu không nhập
    });

    setNewTask({ title: '', assigneeId: '', startDate: '', deadline: '', penalty: '' });
    alert("Đã giao việc thành công");
  };

  const formatDate = (dateString) => {
    if (!dateString) return 'N/A';
    return new Date(dateString).toLocaleString('vi-VN', { hour: '2-digit', minute:'2-digit', day: '2-digit', month: '2-digit', year: 'numeric' });
  };

  return (
    <div>
      <h2>Giao đầu việc & Thiết lập Kỷ luật</h2>
      <form onSubmit={handleCreateTask} style={{ marginBottom: '30px', padding: '20px', background: '#fff', border: '1px solid #ddd', borderRadius: '8px', boxShadow: '0 2px 5px rgba(0,0,0,0.1)' }}>
        
        {/* Dòng 1: Tên việc và Nhân sự */}
        <div style={{ display: 'flex', gap: '15px', marginBottom: '15px' }}>
          <div style={{ flex: 1 }}>
            <label style={{ display: 'block', marginBottom: '5px', fontWeight: 'bold' }}>Tên đầu việc:</label>
            <input 
              placeholder="Ví dụ: Làm báo cáo tháng..." 
              value={newTask.title} 
              onChange={e => setNewTask({...newTask, title: e.target.value})} 
              required 
              style={{ width: '100%', padding: '8px', boxSizing: 'border-box' }}
            />
          </div>
          <div style={{ flex: 1 }}>
            <label style={{ display: 'block', marginBottom: '5px', fontWeight: 'bold' }}>Giao cho:</label>
            <select 
              value={newTask.assigneeId} 
              onChange={e => setNewTask({...newTask, assigneeId: e.target.value})} 
              required 
              style={{ width: '100%', padding: '8px', boxSizing: 'border-box' }}
            >
              <option value="">-- Chọn nhân sự --</option>
              {staffList.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
            </select>
          </div>
        </div>

        {/* Dòng 2: Thời gian */}
        <div style={{ display: 'flex', gap: '15px', marginBottom: '15px' }}>
          <div style={{ flex: 1 }}>
            <label style={{ display: 'block', marginBottom: '5px', fontWeight: 'bold' }}>Bắt đầu:</label>
            <input 
              type="datetime-local"
              value={newTask.startDate} 
              onChange={e => setNewTask({...newTask, startDate: e.target.value})} 
              required 
              style={{ width: '100%', padding: '8px', boxSizing: 'border-box' }}
            />
          </div>
          <div style={{ flex: 1 }}>
            <label style={{ display: 'block', marginBottom: '5px', fontWeight: 'bold' }}>Hạn chót (Deadline):</label>
            <input 
              type="datetime-local"
              value={newTask.deadline} 
              onChange={e => setNewTask({...newTask, deadline: e.target.value})} 
              required 
              style={{ width: '100%', padding: '8px', boxSizing: 'border-box' }}
            />
          </div>
        </div>

        {/* Dòng 3: Hình thức kỷ luật & Nút submit */}
        <div style={{ display: 'flex', gap: '15px', alignItems: 'flex-end' }}>
          <div style={{ flex: 2 }}>
            <label style={{ display: 'block', marginBottom: '5px', fontWeight: 'bold', color: 'red' }}>Hình thức kỷ luật (nếu trễ/không làm):</label>
            <input 
              placeholder="Ví dụ: Trừ 200k lương, Phạt trực nhật..." 
              value={newTask.penalty} 
              onChange={e => setNewTask({...newTask, penalty: e.target.value})} 
              style={{ width: '100%', padding: '8px', boxSizing: 'border-box', border: '1px solid red' }}
            />
          </div>
          <div style={{ flex: 1 }}>
            <button 
              type="submit" 
              style={{ 
                width: '100%',
                background: '#003366', 
                color: 'white', 
                border: 'none', 
                padding: '10px', 
                borderRadius: '5px', 
                fontWeight: 'bold', 
                cursor: 'pointer' 
              }}
            >
              KHỞI TẠO CÔNG VIỆC
            </button>
          </div>
        </div>
      </form>

      <h3>Danh sách công việc đang theo dõi</h3>
      <ul style={{ listStyle: 'none', padding: 0 }}>
        {tasks.map(t => {
          const staff = staffList.find(s => s.id === t.assigneeId);
          return (
            <li key={t.id} style={{ padding: '15px', borderBottom: '1px solid #eee', background: 'white', marginBottom: '10px', borderRadius: '5px' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                <span style={{ fontSize: '1.1rem', fontWeight: 'bold' }}>{t.title}</span>
                <span style={{ color: t.progress === 100 ? 'green' : 'orange', fontWeight: 'bold' }}>{t.progress}%</span>
              </div>
              <div style={{ marginTop: '5px', fontSize: '0.9rem', color: '#555' }}>
                Người thực hiện: <strong>{staff?.name}</strong> <br/>
                Thời gian: {formatDate(t.startDate)} - {formatDate(t.deadline)} <br/>
                <span style={{ color: 'red' }}>Phạt: {t.penalty}</span>
              </div>
            </li>
          );
        })}
      </ul>
    </div>
  );
};

export default TaskManager;
